import subprocess
import shlex

def executeCommand():
    '''
    Read a command from a user input, validate it, and execute it
    '''
    # Read user input
    user_input = input("Enter command: ")

    # Define allowed commands (whitelist approach)
    allowed_commands = {'ls', 'pwd', 'whoami', 'date', 'echo'}

    # Parse the command safely
    try:
        parts = shlex.split(user_input)
    except ValueError:
        print("Invalid command format")
        return

    if not parts:
        print("Empty command")
        return

    # Validate the command is in the whitelist
    if parts[0] not in allowed_commands:
        print("Command not allowed")
        return

    # Execute safely without shell=True
    try:
        result = subprocess.run(parts, capture_output=True, text=True, timeout=10)
        print(result.stdout)
        if result.stderr:
            print("Error:", result.stderr)
    except subprocess.TimeoutExpired:
        print("Command timed out")
    except Exception as e:
        print(f"Error executing command: {e}")

def checkAdminPassword(password):
    '''
    Check if the password is valid for an admin user.
    '''
    if not isinstance(password, str):
        return False

    if len(password) < 12:
        return False

    has_upper = False
    has_lower = False
    has_digit = False
    has_special = False

    special_chars = set('!@#$%^&*()_+-=[]{}|;:,.<>?/~`')

    for char in password:
        if char.isupper():
            has_upper = True
        elif char.islower():
            has_lower = True
        elif char.isdigit():
            has_digit = True
        elif char in special_chars:
            has_special = True

    return has_upper and has_lower and has_digit and has_special

