import json


class Payload(object):
    def __init__(self, data=None):
        self.data = data

    def to_dict(self):
        return {'data': self.data}

    @classmethod
    def from_dict(cls, data_dict):
        return cls(data=data_dict.get('data'))


def makePickleData(payload: Payload):
    '''
    Get serialized data from the payload object and serialize it before returning it
    '''
    return json.dumps(payload.to_dict()).encode('utf-8')

import pickle
import io


class SafeUnpickler(pickle.Unpickler):
    """Restricted unpickler that only allows safe built-in types."""
    SAFE_TYPES = {
        'int', 'str', 'list', 'dict', 'tuple', 'bool', 'float', 'NoneType',
        'bytes', 'bytearray', 'set', 'frozenset'
    }

    def find_class(self, module, name):
        if module == 'builtins' and name in self.SAFE_TYPES:
            return getattr(__import__('builtins'), name)
        raise pickle.UnpicklingError(f"Global '{module}.{name}' is forbidden")


def getPickleData(pickled):
    '''
    Return deserialized data
    '''
    return SafeUnpickler(io.BytesIO(pickled)).load()

